1	-------------------------------------------------------------------------------
2	-- Title      : AxiStreamPackerizerV0 Protocol: https://confluence.slac.stanford.edu/x/1oyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: AXI stream Depacketizer Module (non-interleave only)
7	--    Formats an AXI-Stream for a transport link.
8	--    Sideband fields are placed into the data stream in a header.
9	--    Long frames are broken into smaller packets.
10	-------------------------------------------------------------------------------
11	-- This file is part of 'SLAC Firmware Standard Library'.
12	-- It is subject to the license terms in the LICENSE.txt file found in the
13	-- top-level directory of this distribution and at:
14	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
15	-- No part of 'SLAC Firmware Standard Library', including this file,
16	-- may be copied, modified, propagated, or distributed except according to
17	-- the terms contained in the LICENSE.txt file.
18	-------------------------------------------------------------------------------
19	
20	library ieee;
21	use ieee.std_logic_1164.all;
22	use ieee.numeric_std.all;
23	
24	library surf;
25	use surf.StdRtlPkg.all;
26	use surf.AxiStreamPkg.all;
27	use surf.SsiPkg.all;
28	
29	entity AxiStreamPacketizer is
30	   generic (
31	      TPD_G                : time            := 1 ns;
32	      RST_ASYNC_G          : boolean         := false;
33	      MAX_PACKET_BYTES_G   : integer         := 1440;  -- Must be a multiple of 8
34	      MIN_TKEEP_G          : slv(7 downto 0) := x"01";
35	      OUTPUT_SSI_G         : boolean         := true;  -- SSI compliant output (SOF on tuser)
36	      INPUT_PIPE_STAGES_G  : integer         := 0;
37	      OUTPUT_PIPE_STAGES_G : integer         := 0);
38	   port (
39	      -- AXI-Lite Interface for local registers
40	      axisClk : in sl;
41	      axisRst : in sl;
42	
43	      -- Actual byte count; will be truncated to multiple of word-size
44	      maxPktBytes : in slv(bitSize(MAX_PACKET_BYTES_G) - 1 downto 0) := toSlv(MAX_PACKET_BYTES_G, bitSize(MAX_PACKET_BYTES_G));
45	
46	      sAxisMaster : in  AxiStreamMasterType;
47	      sAxisSlave  : out AxiStreamSlaveType;
48	
49	      mAxisMaster : out AxiStreamMasterType;
50	      mAxisSlave  : in  AxiStreamSlaveType);
51	end entity AxiStreamPacketizer;
52	
53	architecture rtl of AxiStreamPacketizer is
54	
55	   constant LD_WORD_SIZE_C : positive := 3;
56	   constant WORD_SIZE_C    : positive := 2**LD_WORD_SIZE_C;
57	
58	   subtype WordCounterType is unsigned(maxPktBytes'left - LD_WORD_SIZE_C downto 0);
59	
60	   constant PROTO_WORDS_C    : positive        := 3;
61	   constant MAX_WORD_COUNT_C : WordCounterType := to_unsigned(MAX_PACKET_BYTES_G / WORD_SIZE_C, WordCounterType'length);
62	
63	   constant AXIS_CONFIG_C : AxiStreamConfigType := (
64	      TSTRB_EN_C    => false,
65	      TDATA_BYTES_C => 8,
66	      TDEST_BITS_C  => 0,
67	      TID_BITS_C    => 0,
68	      TKEEP_MODE_C  => TKEEP_NORMAL_C,
69	      TUSER_BITS_C  => ite(OUTPUT_SSI_G, 2, 0),
70	      TUSER_MODE_C  => TUSER_FIRST_LAST_C);
71	
72	   constant VERSION_C : slv(3 downto 0) := "0000";
73	
74	   type StateType is (
75	      IDLE_S,
76	      MOVE_S,
77	      TAIL_S);
78	
79	   type RegType is record
80	      state            : StateType;
81	      frameNumber      : unsigned(11 downto 0);
82	      packetNumber     : unsigned(23 downto 0);
83	      wordCount        : WordCounterType;
84	      maxWords         : WordCounterType;
85	      eof              : sl;
86	      tUserLast        : slv(7 downto 0);
87	      inputAxisSlave   : AxiStreamSlaveType;
88	      outputAxisMaster : AxiStreamMasterType;
89	   end record RegType;
90	
91	   constant REG_INIT_C : RegType := (
92	      state            => IDLE_S,
93	      frameNumber      => (others => '0'),
94	      packetNumber     => (others => '0'),
95	      wordCount        => (others => '0'),
96	      maxWords         => to_unsigned(1, WordCounterType'length),
97	      eof              => '0',
98	      tUserLast        => (others => '0'),
99	      inputAxisSlave   => AXI_STREAM_SLAVE_INIT_C,
100	      outputAxisMaster => axiStreamMasterInit(AXIS_CONFIG_C));
101	
102	   signal r   : RegType := REG_INIT_C;
103	   signal rin : RegType;
104	
105	   signal inputAxisMaster  : AxiStreamMasterType;
106	   signal inputAxisSlave   : AxiStreamSlaveType;
107	   signal outputAxisMaster : AxiStreamMasterType;
108	   signal outputAxisSlave  : AxiStreamSlaveType;
109	
110	   signal maxWords : WordCounterType;
111	
112	   -- attribute dont_touch                     : string;
113	   -- attribute dont_touch of r                : signal is "TRUE";
114	   -- attribute dont_touch of inputAxisMaster  : signal is "TRUE";
115	   -- attribute dont_touch of inputAxisSlave   : signal is "TRUE";
116	   -- attribute dont_touch of outputAxisMaster : signal is "TRUE";
117	   -- attribute dont_touch of outputAxisSlave  : signal is "TRUE";
118	
119	begin
120	
121	   assert ((MAX_PACKET_BYTES_G rem 8) = 0)
122	      report "MAX_PACKET_BYTES_G must be a multiple of 8" severity failure;
123	
124	   maxWords <= WordCounterType(maxPktBytes(maxPktBytes'left downto LD_WORD_SIZE_C));
125	
126	   -----------------
127	   -- Input pipeline
128	   -----------------
129	   U_Input : entity surf.AxiStreamPipeline
130	      generic map (
131	         TPD_G         => TPD_G,
132	         RST_ASYNC_G   => RST_ASYNC_G,
133	         PIPE_STAGES_G => INPUT_PIPE_STAGES_G)
134	      port map (
135	         axisClk     => axisClk,
136	         axisRst     => axisRst,
137	         sAxisMaster => sAxisMaster,
138	         sAxisSlave  => sAxisSlave,
139	         mAxisMaster => inputAxisMaster,
140	         mAxisSlave  => inputAxisSlave);
141	
142	   comb : process (axisRst, inputAxisMaster, maxWords, outputAxisSlave, r) is
143	      variable v    : RegType;
144	      variable fits : boolean;
145	
146	   begin
147	      -- Latch the current value
148	      v := r;
149	
150	      -- Reset tready by default
151	      v.inputAxisSlave.tready := '0';
152	
153	      -- Check if data accepted
154	      if (outputAxisSlave.tReady = '1') then
155	         v.outputAxisMaster.tValid := '0';
156	      end if;
157	
158	      case r.state is
159	         ----------------------------------------------------------------------
160	         when IDLE_S =>
161	            -- Reset the counter
162	            v.wordCount := (others => '0');
163	
164	            -- Check and register the max. word count
165	            -- NOTE: wordCount is compared only after incrementing
166	            --       (and doing some work in MOVE_S), thus at least
167	            --       one non-protocol word  must fit.
168	            if (maxWords <= to_unsigned(PROTO_WORDS_C, maxWords'length)) then
169	               fits := false;
170	            else
171	               fits := true;
172	               if (maxWords >= MAX_WORD_COUNT_C) then
173	                  v.maxWords := MAX_WORD_COUNT_C - PROTO_WORDS_C;
174	               else
175	                  v.maxWords := maxWords - PROTO_WORDS_C;
176	               end if;
177	            end if;
178	
179	            -- Check if ready to move data
180	            if (fits and inputAxisMaster.tValid = '1' and v.outputAxisMaster.tValid = '0') then
181	               -- Initialize the AXIS buffer
182	               v.outputAxisMaster                     := axiStreamMasterInit(AXIS_CONFIG_C);
183	               -- Generate the 64-bit header
184	               v.outputAxisMaster.tValid              := '1';
185	               v.outputAxisMaster.tData(3 downto 0)   := VERSION_C;
186	               v.outputAxisMaster.tData(15 downto 4)  := slv(r.frameNumber);
187	               v.outputAxisMaster.tData(39 downto 16) := slv(r.packetNumber);
188	               v.outputAxisMaster.tData(47 downto 40) := inputAxisMaster.tDest(7 downto 0);
189	               v.outputAxisMaster.tData(55 downto 48) := inputAxisMaster.tId(7 downto 0);
190	               v.outputAxisMaster.tData(63 downto 56) := inputAxisMaster.tUser(7 downto 0);
191	               -- Check if SSI output
192	               if (OUTPUT_SSI_G) then
193	                  -- Set the SOF bit
194	                  axiStreamSetUserBit(AXIS_CONFIG_C, v.outputAxisMaster, SSI_SOF_C, '1', 0);  -- SOF
195	               end if;
196	               -- Increment the counter
197	               v.packetNumber := r.packetNumber + 1;
198	               -- Next state
199	               v.state        := MOVE_S;
200	            end if;
201	         ----------------------------------------------------------------------
202	         when MOVE_S =>
203	            -- Check if ready to move data
204	            if (inputAxisMaster.tValid = '1' and v.outputAxisMaster.tValid = '0') then
205	
206	               -- Accept the data
207	               v.inputAxisSlave.tReady := '1';
208	
209	               -- Send data through
210	               v.outputAxisMaster       := inputAxisMaster;
211	               v.outputAxisMaster.tUser := (others => '0');
212	               v.outputAxisMaster.tDest := (others => '0');
213	               v.outputAxisMaster.tId   := (others => '0');
214	               v.outputAxisMaster.tKeep := resize(x"00FF", AXI_STREAM_MAX_TKEEP_WIDTH_C);
215	
216	               -- Increment word count with each txn
217	               v.wordCount := r.wordCount + 1;
218	
219	               -- Reach max packet size. Append tail.
220	               if (r.wordCount = r.maxWords) then
221	                  -- Next state
222	                  v.state := TAIL_S;
223	               end if;
224	
225	               -- Check for the end of the frame
226	               if (inputAxisMaster.tLast = '1') then
227	
228	                  -- Increment the counter
229	                  v.frameNumber  := r.frameNumber + 1;
230	                  -- Reset the counter
231	                  v.packetNumber := (others => '0');
232	                  -- Next state
233	                  v.state        := IDLE_S;
234	
235	                  ----------------------------------------------------------------------
236	                  -- Generate the TAIL with respect to the TKEEP
237	                  ----------------------------------------------------------------------
238	                  case (inputAxisMaster.tKeep(7 downto 0)) is
239	                     when x"00" =>
240	                        v.outputAxisMaster.tKeep(7 downto 0) := (x"01" or MIN_TKEEP_G);
241	                        v.outputAxisMaster.tData(7 downto 0) := '1' & inputAxisMaster.tUser(6 downto 0);
242	                     when x"01" =>
243	                        v.outputAxisMaster.tKeep(7 downto 0)  := (x"03" or MIN_TKEEP_G);
244	                        v.outputAxisMaster.tData(15 downto 8) := '1' & inputAxisMaster.tUser(14 downto 8);
245	                     when x"03" =>
246	                        v.outputAxisMaster.tKeep(7 downto 0)   := (x"07" or MIN_TKEEP_G);
247	                        v.outputAxisMaster.tData(23 downto 16) := '1' & inputAxisMaster.tUser(22 downto 16);
248	                     when x"07" =>
249	                        v.outputAxisMaster.tKeep(7 downto 0)   := (x"0F" or MIN_TKEEP_G);
250	                        v.outputAxisMaster.tData(31 downto 24) := '1' & inputAxisMaster.tUser(30 downto 24);
251	                     when x"0F" =>
252	                        v.outputAxisMaster.tKeep(7 downto 0)   := (x"1F" or MIN_TKEEP_G);
253	                        v.outputAxisMaster.tData(39 downto 32) := '1' & inputAxisMaster.tUser(38 downto 32);
254	                     when x"1F" =>
255	                        v.outputAxisMaster.tKeep(7 downto 0)   := (x"3F" or MIN_TKEEP_G);
256	                        v.outputAxisMaster.tData(47 downto 40) := '1' & inputAxisMaster.tUser(46 downto 40);
257	                     when x"3F" =>
258	                        v.outputAxisMaster.tKeep(7 downto 0)   := (x"7F" or MIN_TKEEP_G);
259	                        v.outputAxisMaster.tData(55 downto 48) := '1' & inputAxisMaster.tUser(54 downto 48);
260	                     when x"7F" =>
261	                        v.outputAxisMaster.tKeep(7 downto 0)   := (x"FF" or MIN_TKEEP_G);
262	                        v.outputAxisMaster.tData(63 downto 56) := '1' & inputAxisMaster.tUser(62 downto 56);
263	                     when others =>
264	                        -- No room for TAIL this cycle and will add it in the next state
265	                        v.outputAxisMaster.tKeep(7 downto 0) := (x"FF" or MIN_TKEEP_G);
266	                        -- Save the tUser at tLast
267	                        v.tUserLast                          := inputAxisMaster.tUser(7 downto 0);
268	                        -- Set the flag
269	                        v.eof                                := '1';
270	                        -- Reset the flag
271	                        v.outputAxisMaster.tLast             := '0';
272	                        -- Next state
273	                        v.state                              := TAIL_S;
274	                  end case;
275	                  ----------------------------------------------------------------------
276	
277	               end if;
278	            end if;
279	         ----------------------------------------------------------------------
280	         when TAIL_S =>
281	            -- Check if ready to move data
282	            if (v.outputAxisMaster.tValid = '0') then
283	               -- Generate the footer
284	               v.outputAxisMaster.tValid            := '1';
285	               v.outputAxisMaster.tKeep(7 downto 0) := MIN_TKEEP_G;  --x"01";
286	               v.outputAxisMaster.tData             := (others => '0');
287	               v.outputAxisMaster.tData(7)          := r.eof;
288	               v.outputAxisMaster.tData(6 downto 0) := r.tUserLast(6 downto 0);
289	               v.outputAxisMaster.tUser             := (others => '0');
290	               v.outputAxisMaster.tLast             := '1';
291	               -- Set the flag
292	               v.eof                                := '0';
293	               -- Next state
294	               v.state                              := IDLE_S;
295	            end if;
296	         ----------------------------------------------------------------------
297	         when others =>  -- For ASIC designs it is best to declare a 'Default' state which returns to IDLE_S state
298	            v := REG_INIT_C;
299	      ----------------------------------------------------------------------
300	      end case;
301	
302	      -- Match the tStrobe to tKeep
303	      v.outputAxisMaster.tStrb := v.outputAxisMaster.tKeep;
304	
305	      -- Combinatorial outputs before the reset
306	      inputAxisSlave <= v.inputAxisSlave;
307	
308	      -- Reset
309	      if (RST_ASYNC_G = false and axisRst = '1') then
310	         v := REG_INIT_C;
311	      end if;
312	
313	      -- Register the variable for next clock cycle
314	      rin <= v;
315	
316	      -- Registered Outputs
317	      outputAxisMaster <= r.outputAxisMaster;
318	
319	   end process comb;
320	
321	   seq : process (axisClk, axisRst) is
322	   begin
323	      if (RST_ASYNC_G and axisRst = '1') then
324	         r <= REG_INIT_C after TPD_G;
325	      elsif rising_edge(axisClk) then
326	         r <= rin after TPD_G;
327	      end if;
328	   end process seq;
329	
330	   ------------------
331	   -- Output pipeline
332	   ------------------
333	   U_Output : entity surf.AxiStreamPipeline
334	      generic map (
335	         TPD_G         => TPD_G,
336	         RST_ASYNC_G   => RST_ASYNC_G,
337	         PIPE_STAGES_G => OUTPUT_PIPE_STAGES_G)
338	      port map (
339	         axisClk     => axisClk,
340	         axisRst     => axisRst,
341	         sAxisMaster => outputAxisMaster,
342	         sAxisSlave  => outputAxisSlave,
343	         mAxisMaster => mAxisMaster,
344	         mAxisSlave  => mAxisSlave);
345	
346	end architecture rtl;
347

