16	-------------------------------------------------------------------------------
17	
18	library ieee;
19	use ieee.std_logic_1164.all;
20	use ieee.std_logic_unsigned.all;
21	use ieee.std_logic_arith.all;
22	
23	library surf;
24	use surf.StdRtlPkg.all;
25	use surf.AxiStreamPkg.all;
26	use surf.SsiPkg.all;
27	
28	entity AxiStreamBatcher is
29	   generic (
30	      TPD_G                        : time                  := 1 ns;
31	      VERSION_G                    : positive range 1 to 2 := 1;
32	      MAX_NUMBER_SUB_FRAMES_G      : positive              := 32;  -- Units of sub-frames
33	      SUPER_FRAME_BYTE_THRESHOLD_G : natural               := 8192;  -- Units of bytes
34	      MAX_CLK_GAP_G                : natural               := 256;  -- Units of clock cycles
35	      AXIS_CONFIG_G                : AxiStreamConfigType;
36	      INPUT_PIPE_STAGES_G          : natural               := 0;
37	      OUTPUT_PIPE_STAGES_G         : natural               := 1);
38	   port (
39	      -- Clock and Reset
40	      axisClk                 : in  sl;
41	      axisRst                 : in  sl;
42	      -- External Control Interface
43	      forceTerm               : in  sl               := '0';
44	      superFrameByteThreshold : in  slv(31 downto 0) := toSlv(SUPER_FRAME_BYTE_THRESHOLD_G, 32);
45	      maxSubFrames            : in  slv(15 downto 0) := toSlv(MAX_NUMBER_SUB_FRAMES_G, 16);
46	      maxClkGap               : in  slv(31 downto 0) := toSlv(MAX_CLK_GAP_G, 32);
47	      idle                    : out sl;
48	      -- AXIS Interfaces
49	      sAxisMaster             : in  AxiStreamMasterType;
50	      sAxisSlave              : out AxiStreamSlaveType;
51	      mAxisMaster             : out AxiStreamMasterType;
52	      mAxisSlave              : in  AxiStreamSlaveType);
53	end entity AxiStreamBatcher;
54	
55	architecture rtl of AxiStreamBatcher is
56	
57	   constant AXIS_WORD_SIZE_C : positive := AXIS_CONFIG_G.TDATA_BYTES_C;  -- Units of bytes
58	
59	   constant WIDTH_C : slv(3 downto 0) := toSlv(log2(AXIS_WORD_SIZE_C/2), 4);
60	
61	   type StateType is (
62	      HEADER_S,
63	      SUB_FRAME_S,
64	      TAIL_S,
65	      CHUNK_TAIL_2BYTE_S,
66	      CHUNK_TAIL_4BYTE_S,
67	      GAP_S);
68	
69	   type RegType is record
70	      superFrameByteThreshold    : slv(31 downto 0);
71	      superByteCnt               : slv(31 downto 0);
72	      subByteCnt                 : slv(31 downto 0);
73	      maxSubFrames               : slv(15 downto 0);
74	      subFrameCnt                : slv(15 downto 0);
75	      maxClkGap                  : slv(31 downto 0);
76	      clkGapCnt                  : slv(31 downto 0);
77	      superFrameByteThresholdDet : sl;
78	      maxSubFramesDet            : sl;
79	      forceTerm                  : sl;
80	      seqCnt                     : slv(7 downto 0);
81	      tDest                      : slv(7 downto 0);
82	      tUserFirst                 : slv(7 downto 0);
83	      tUserLast                  : slv(7 downto 0);
84	      chunkCnt                   : natural range 0 to 3;
85	      rxSlave                    : AxiStreamSlaveType;
86	      txMaster                   : AxiStreamMasterType;
87	      state                      : StateType;
88	   end record RegType;
89	
90	   constant REG_INIT_C : RegType := (
91	      superFrameByteThreshold    => toSlv(SUPER_FRAME_BYTE_THRESHOLD_G, 32),
92	      superByteCnt               => toSlv(AXIS_WORD_SIZE_C, 32),
93	      subByteCnt                 => (others => '0'),
94	      maxSubFrames               => toSlv(MAX_NUMBER_SUB_FRAMES_G, 16),
95	      subFrameCnt                => (others => '0'),
96	      maxClkGap                  => toSlv(MAX_CLK_GAP_G, 32),
97	      clkGapCnt                  => (others => '0'),
98	      superFrameByteThresholdDet => '0',
99	      maxSubFramesDet            => '0',
100	      forceTerm                  => '0',
101	      seqCnt                     => (others => '0'),
102	      tDest                      => (others => '0'),
103	      tUserFirst                 => (others => '0'),
104	      tUserLast                  => (others => '0'),
105	      chunkCnt                   => 1,
106	      rxSlave                    => AXI_STREAM_SLAVE_INIT_C,
107	      txMaster                   => axiStreamMasterInit(AXIS_CONFIG_G),
108	      state                      => HEADER_S);
109	
110	   signal r   : RegType := REG_INIT_C;
111	   signal rin : RegType;
112	
113	   signal rxMaster : AxiStreamMasterType;
114	   signal rxSlave  : AxiStreamSlaveType;
115	   signal txMaster : AxiStreamMasterType;
116	   signal txSlave  : AxiStreamSlaveType;
117	
118	begin
119	
120	   assert (AXIS_WORD_SIZE_C >= 2)
121	      report "AXIS_CONFIG_G.TDATA_BYTES_C must be >= 2" severity failure;
122	
123	   assert (VERSION_G = 2) or ((VERSION_G = 1) and isPowerOf2(AXIS_WORD_SIZE_C))
124	      report "Batcher Version1: AXIS_CONFIG_G.TDATA_BYTES_C must be power of 2" severity failure;
125	
126	   assert (VERSION_G = 1) or ((VERSION_G = 2) and (AXIS_WORD_SIZE_C >= 8))
127	      report "Batcher Version2: AXIS_CONFIG_G.TDATA_BYTES_C must be >= 8" severity failure;
128	
129	   -----------------
130	   -- Input pipeline
131	   -----------------
132	   U_Input : entity surf.AxiStreamPipeline
133	      generic map (
134	         TPD_G         => TPD_G,
135	         PIPE_STAGES_G => INPUT_PIPE_STAGES_G)
136	      port map (
137	         axisClk     => axisClk,
138	         axisRst     => axisRst,
139	         sAxisMaster => sAxisMaster,
140	         sAxisSlave  => sAxisSlave,
141	         mAxisMaster => rxMaster,
142	         mAxisSlave  => rxSlave);
143	
144	   comb : process (axisRst, forceTerm, maxClkGap, maxSubFrames, r, rxMaster,
145	                   superFrameByteThreshold, txSlave) is
146	      variable v : RegType;
147	
148	      procedure doTail is
149	      begin
150	         -- Check for end of super-frame condition
151	         if (v.superFrameByteThresholdDet = '1') or (v.maxSubFramesDet = '1') or (v.forceTerm = '1') then
152	            -- Move the outbound data
153	            v.txMaster.tValid := '1';
154	            -- Terminate the super-frame
155	            v.txMaster.tLast  := '1';
156	            -- Set EOFE
157	            ssiSetUserEofe(AXIS_CONFIG_G, v.txMaster, v.forceTerm);
158	            -- Next state
159	            v.state           := HEADER_S;
160	         -- Check if new data to move or bypassing clock gap
161	         elsif (rxMaster.tValid = '1') or (r.maxClkGap = 0) then
162	            -- Move the outbound data
163	            v.txMaster.tValid := '1';
164	            -- Next state
165	            v.state           := SUB_FRAME_S;
166	         else
167	            -- Next state
168	            v.state := GAP_S;
169	         end if;
170	      end procedure doTail;
171	
172	   begin
173	      -- Latch the current value
174	      v := r;
175	
176	      -- Reset the strobes
177	      v.rxSlave.tReady := r.forceTerm;
178	      if (txSlave.tReady = '1') then
179	         v.txMaster := axiStreamMasterInit(AXIS_CONFIG_G);
180	      end if;
181	
182	      -- Check for max. super frame
183	      if(r.superByteCnt = r.superFrameByteThreshold) and (r.superFrameByteThreshold /= 0) then
184	         -- Set the flag
185	         v.superFrameByteThresholdDet := '1';
186	      end if;
187	
188	      -- Check for max. super frame
189	      if(r.subFrameCnt = r.maxSubFrames) then
190	         -- Set the flag
191	         v.maxSubFramesDet := '1';
192	      end if;
193	
194	      -- Register the value
195	      v.forceTerm := forceTerm;
196	
197	      -- Main state machine
198	      case r.state is
199	         ----------------------------------------------------------------------
200	         when HEADER_S =>
201	            -- Reset the flag
202	            v.superFrameByteThresholdDet                                    := '0';
203	            v.maxSubFramesDet                                               := '0';
204	            -- Sample external signals
205	            v.superFrameByteThreshold                                       := superFrameByteThreshold;
206	            v.maxSubFrames                                                  := maxSubFrames;
207	            v.maxClkGap                                                     := maxClkGap;
208	            -- Floor the superFrameByteThreshold to nearest word increment
209	            -- This is done to remove the ">" operator
210	            v.superFrameByteThreshold(bitSize(AXIS_WORD_SIZE_C)-1 downto 0) := (others => '0');
211	            -- Check for zero byte superFrameByteThreshold case and not using a zero value external threshold
212	            if (v.superFrameByteThreshold = 0) and (superFrameByteThreshold /= 0) then
213	               -- Prevent zero case
214	               v.superFrameByteThreshold := toSlv(AXIS_WORD_SIZE_C, 32);
215	            end if;
216	            -- Check for zero maxSubFrames case
217	            if (v.maxSubFrames = 0) then
218	               -- Prevent zero case
219	               v.maxSubFrames := toSlv(1, 16);
220	            end if;
221	            -- Check if ready to move data
222	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') and (r.forceTerm = '0') then
223	               -- Send the super-frame header
224	               v.txMaster.tValid               := '1';
225	               v.txMaster.tData(3 downto 0)    := toSlv(VERSION_G, 4);  -- Version = 0x1 or 0x2
226	               v.txMaster.tData(7 downto 4)    := WIDTH_C;  -- Only used in Version 1
227	               v.txMaster.tData(15 downto 8)   := r.seqCnt;
228	               v.txMaster.tData(127 downto 16) := (others => '0');
229	               ssiSetUserSof(AXIS_CONFIG_G, v.txMaster, '1');
230	               -- Check for Version 2
231	               if (VERSION_G = 2) then
232	                  -- No zero padding in Version 2
233	                  v.txMaster.tKeep := genTKeep(2);  -- 2 byte super-frame header
234	                  v.txMaster.tStrb := genTKeep(2);  -- 2 byte super-frame header
235	               end if;
236	               -- Increment the sequence counter
237	               v.seqCnt := r.seqCnt + 1;
238	               -- Next state
239	               v.state  := SUB_FRAME_S;
240	            end if;
241	            -- Reset the sub-frame counter
242	            v.subFrameCnt  := (others => '0');
243	            -- Preset the super-frame byte counter
244	            v.superByteCnt := toSlv(AXIS_WORD_SIZE_C, 32);
245	         ----------------------------------------------------------------------
246	         when SUB_FRAME_S =>
247	            -- Check if ready to move data
248	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
249	               -- Accept the inbound data
250	               v.rxSlave.tReady  := '1';
251	               -- Move the outbound data
252	               v.txMaster.tValid := '1';
253	               v.txMaster.tData  := rxMaster.tData;
254	               -- Check if first transaction
255	               if (r.subByteCnt = 0) then
256	                  -- Sample the first transaction
257	                  v.tUserFirst(AXIS_CONFIG_G.TUSER_BITS_C-1 downto 0) := axiStreamGetUserField(AXIS_CONFIG_G, rxMaster, 0);
258	                  -- Increment the sub-frame counter
259	                  v.subFrameCnt                                       := r.subFrameCnt + 1;
260	               end if;
261	               -- Check for last transaction in sub-frame
262	               if (rxMaster.tLast = '1') then
263	                  -- Increment the sub-frame byte counter
264	                  v.subByteCnt                                       := r.subByteCnt + getTKeep(rxMaster.tKeep, AXIS_CONFIG_G);
265	                  -- Sample the meta data
266	                  v.tUserLast(AXIS_CONFIG_G.TUSER_BITS_C-1 downto 0) := axiStreamGetUserField(AXIS_CONFIG_G, rxMaster);
267	                  v.tDest(AXIS_CONFIG_G.TDEST_BITS_C-1 downto 0)     := rxMaster.tDest(AXIS_CONFIG_G.TDEST_BITS_C-1 downto 0);
268	                  -- Next state
269	                  v.state                                            := TAIL_S;
270	                  -- Check for Version 2
271	                  if (VERSION_G = 2) then
272	                     -- No zero padding in Version 2
273	                     v.txMaster.tKeep := rxMaster.tKeep;
274	                     v.txMaster.tStrb := rxMaster.tKeep;
275	                  end if;
276	               else
277	                  -- Increment the sub-frame byte counter
278	                  v.subByteCnt := r.subByteCnt + AXIS_WORD_SIZE_C;
279	               end if;
280	               -- Increment the super-frame byte counter
281	               v.superByteCnt := r.superByteCnt + AXIS_WORD_SIZE_C;
282	            end if;
283	         ----------------------------------------------------------------------
284	         when TAIL_S =>
285	            -- Check if ready to move data
286	            if (v.txMaster.tValid = '0') then
287	               -- Set the sub-frame tail data field
288	               v.txMaster.tData               := (others => '0');
289	               v.txMaster.tData(31 downto 0)  := r.subByteCnt;
290	               v.txMaster.tData(39 downto 32) := r.tDest;
291	               v.txMaster.tData(47 downto 40) := r.tUserFirst;
292	               v.txMaster.tData(55 downto 48) := r.tUserLast;
293	               v.txMaster.tData(59 downto 56) := WIDTH_C;  -- Only used in Version 1
294	               -- Check for Version 2
295	               if (VERSION_G = 2) then
296	                  -- No zero padding in Version 2
297	                  v.txMaster.tKeep := genTKeep(7);  -- 7 byte sub-frame tail
298	                  v.txMaster.tStrb := genTKeep(7);  -- 7 byte sub-frame tail
299	               end if;
300	               -- Reset the counter
301	               v.subByteCnt := (others => '0');
302	               -- Check the AXIS width
303	               if (AXIS_WORD_SIZE_C = 2) then
304	                  -- Move the outbound data
305	                  v.txMaster.tValid := '1';
306	                  -- Next state
307	                  v.state           := CHUNK_TAIL_2BYTE_S;
308	               elsif (AXIS_WORD_SIZE_C = 4) then
309	                  -- Move the outbound data
310	                  v.txMaster.tValid := '1';
311	                  -- Next state
312	                  v.state           := CHUNK_TAIL_4BYTE_S;
313	               else
314	                  -- Process the tail
315	                  doTail;
316	               end if;
317	               -- Preset chunk counter
318	               v.chunkCnt     := 1;
319	               -- Increment the super-frame byte counter
320	               v.superByteCnt := r.superByteCnt + AXIS_WORD_SIZE_C;
321	            end if;
322	         ----------------------------------------------------------------------
323	         when CHUNK_TAIL_2BYTE_S =>
324	            -- Check if ready to move data
325	            if (v.txMaster.tValid = '0') then
326	               -- Shift the data
327	               v.txMaster.tData(63 downto 0) := x"0000" & r.txMaster.tData(63 downto 16);
328	               -- Check the chunking counter
329	               if r.chunkCnt = 3 then
330	                  -- Process the tail
331	                  doTail;
332	               else
333	                  -- Move the outbound data
334	                  v.txMaster.tValid := '1';
335	                  -- Increment the counter
336	                  v.chunkCnt        := r.chunkCnt + 1;
337	               end if;
338	               -- Increment the super-frame byte counter
339	               v.superByteCnt := r.superByteCnt + AXIS_WORD_SIZE_C;
340	            end if;
341	         ----------------------------------------------------------------------
342	         when CHUNK_TAIL_4BYTE_S =>
343	            -- Check if ready to move data
344	            if (v.txMaster.tValid = '0') then
345	               -- Shift the data
346	               v.txMaster.tData(63 downto 0) := x"0000_0000" & r.txMaster.tData(63 downto 32);
347	               -- Check the chunking counter
348	               if r.chunkCnt = 1 then
349	                  -- Process the tail
350	                  doTail;
351	               else
352	                  -- Move the outbound data
353	                  v.txMaster.tValid := '1';
354	                  -- Increment the counter
355	                  v.chunkCnt        := r.chunkCnt + 1;
356	               end if;
357	               -- Increment the super-frame byte counter
358	               v.superByteCnt := r.superByteCnt + AXIS_WORD_SIZE_C;
359	            end if;
360	         ----------------------------------------------------------------------
361	         when GAP_S =>
362	            -- Check for new sub-frame
363	            if (rxMaster.tValid = '1') then
364	               -- Reset the counter
365	               v.clkGapCnt       := (others => '0');
366	               -- Move the data
367	               v.txMaster.tValid := '1';
368	               -- Next state
369	               v.state           := SUB_FRAME_S;
370	            -- Check for the clock gap event
371	            elsif (r.clkGapCnt = r.maxClkGap) then
372	               -- Check if ready to move data
373	               if (v.txMaster.tValid = '0') then
374	                  -- Reset the counter
375	                  v.clkGapCnt       := (others => '0');
376	                  -- Move the outbound data
377	                  v.txMaster.tValid := '1';
378	                  -- Terminate the super-frame
379	                  v.txMaster.tLast  := '1';
380	                  -- Next state
381	                  v.state           := HEADER_S;
382	               end if;
383	            else
384	               -- Increment the counter
385	               v.clkGapCnt := r.clkGapCnt + 1;
386	            end if;
387	      ----------------------------------------------------------------------
388	      end case;
389	
390	      -- Check for force termination
391	      if (r.forceTerm = '1') and (r.state /= HEADER_S) then
392	         doTail;
393	      end if;
394	
395	      -- Outputs
396	      rxSlave  <= v.rxSlave;
397	      txMaster <= r.txMaster;
398	      if (r.state = HEADER_S) then
399	         idle <= '1';
400	      else
401	         idle <= '0';
402	      end if;
403	
404	      -- Reset
405	      if (axisRst = '1') then
406	         v := REG_INIT_C;
407	
408	      end if;
409	
410	      -- Register the variable for next clock cycle
411	      rin <= v;
412	
413	   end process comb;
414	
415	   seq : process (axisClk) is
416	   begin
417	      if (rising_edge(axisClk)) then
418	         r <= rin after TPD_G;
419	      end if;
420	   end process seq;
421	
422	   ------------------
423	   -- Output pipeline
424	   ------------------
425	   GEN_VERSION1 : if (VERSION_G = 1) generate
426	      U_Output : entity surf.AxiStreamPipeline
427	         generic map (
428	            TPD_G         => TPD_G,
429	            PIPE_STAGES_G => OUTPUT_PIPE_STAGES_G)
430	         port map (
431	            axisClk     => axisClk,
432	            axisRst     => axisRst,
433	            sAxisMaster => txMaster,
434	            sAxisSlave  => txSlave,
435	            mAxisMaster => mAxisMaster,
436	            mAxisSlave  => mAxisSlave);
437	   end generate;
438	
439	   ----------------------------------------------------------
440	   -- Output pipeline + Byte Packing for no zero padding gaps
441	   ----------------------------------------------------------
442	   GEN_VERSION2 : if (VERSION_G = 2) generate
443	      U_tKeepPacking : entity surf.AxiStreamGearbox
444	         generic map (
445	            TPD_G                => TPD_G,
446	            PIPE_STAGES_G        => OUTPUT_PIPE_STAGES_G,
447	            FORCE_GEARBOX_IMPL_G => true,
448	            SLAVE_AXI_CONFIG_G   => AXIS_CONFIG_G,
449	            MASTER_AXI_CONFIG_G  => AXIS_CONFIG_G)
450	         port map (
451	            axisClk     => axisClk,
452	            axisRst     => axisRst,
453	            sAxisMaster => txMaster,
454	            sAxisSlave  => txSlave,
455	            mAxisMaster => mAxisMaster,
456	            mAxisSlave  => mAxisSlave);
457	   end generate;
458	
459	end rtl;
