1	-------------------------------------------------------------------------------
2	-- Title      : Line Code 8B10B: https://en.wikipedia.org/wiki/8b/10b_encoding
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: 8B10B Package File
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.numeric_std.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	
24	package Code8b10bPkg is
25	
26	   -------------------------------------------------------------------------------------------------
27	   -- Control Code Constants
28	   -------------------------------------------------------------------------------------------------
29	   constant K_28_0_C : slv(7 downto 0) := "00011100";  -- K28.0, 0x1C
30	   constant K_28_1_C : slv(7 downto 0) := "00111100";  -- K28.1, 0x3C (Comma)
31	   constant K_28_2_C : slv(7 downto 0) := "01011100";  -- K28.2, 0x5C
32	   constant K_28_3_C : slv(7 downto 0) := "01111100";  -- K28.3, 0x7C
33	   constant K_28_4_C : slv(7 downto 0) := "10011100";  -- K28.4, 0x9C
34	   constant K_28_5_C : slv(7 downto 0) := "10111100";  -- K28.5, 0xBC (Comma)
35	   constant K_28_6_C : slv(7 downto 0) := "11011100";  -- K28.6, 0xDC
36	   constant K_28_7_C : slv(7 downto 0) := "11111100";  -- K28.7, 0xFC (Comma)
37	   constant K_23_7_C : slv(7 downto 0) := "11110111";  -- K23.7, 0xF7
38	   constant K_27_7_C : slv(7 downto 0) := "11111011";  -- K27.7, 0xFB
39	   constant K_29_7_C : slv(7 downto 0) := "11111101";  -- K29.7, 0xFD
40	   constant K_30_7_C : slv(7 downto 0) := "11111110";  -- K30.7, 0xFE
41	
42	   constant D_10_2_C : slv(7 downto 0) := "01001010";  -- D10.2, 0x4A
43	   constant D_21_5_C : slv(7 downto 0) := "10110101";  -- D21.5, 0xB5
44	
45	   procedure encode8b10b (
46	      dataIn  : in  slv(7 downto 0);
47	      dataKIn : in  sl;
48	      dispIn  : in  sl;
49	      dataOut : out slv(9 downto 0);
50	      dispOut : out sl);
51	
52	   procedure decode8b10b (
53	      dataIn   : in  slv(9 downto 0);
54	      dispIn   : in  sl;
55	      dataOut  : out slv(7 downto 0);
56	      dataKOut : out sl;
57	      dispOut  : out sl;
58	      codeErr  : out sl;
59	      dispErr  : out sl);
60	
61	end package Code8b10bPkg;
62	
63	package body Code8b10bPkg is
64	
65	   procedure encode8b10b (
66	      dataIn  : in  slv(7 downto 0);
67	      dataKIn : in  sl;
68	      dispIn  : in  sl;
69	      dataOut : out slv(9 downto 0);
70	      dispOut : out sl)
71	   is
72	      variable ai, bi, ci, di, ei, fi, gi, hi, ki     : sl;
73	      variable aeqb, ceqd                             : sl;
74	      variable l22, l40, l04, l13, l31                : sl;
75	      variable ao, bo, co, do, eo, io, fo, go, ho, jo : sl;
76	      variable pd1s6, nd1s6, ndos6, pdos6             : sl;
77	      variable alt6, alt7                             : sl;
78	      variable nd1s4, pd1s4, ndos4, pdos4             : sl;
79	      variable illegalk                               : sl;
80	      variable compls6, disp6, compls4                : sl;
81	   begin
82	
83	      ai := dataIn(0);
84	      bi := dataIn(1);
85	      ci := dataIn(2);
86	      di := dataIn(3);
87	      ei := dataIn(4);
88	      fi := dataIn(5);
89	      gi := dataIn(6);
90	      hi := dataIn(7);
91	      ki := dataKIn;
92	
93	      aeqb := (ai and bi) or (not ai and not bi);
94	      ceqd := (ci and di) or (not ci and not di);
95	      l22  := (ai and bi and not ci and not di) or
96	             (ci and di and not ai and not bi) or
97	             (not aeqb and not ceqd);
98	      l40 := ai and bi and ci and di;
99	      l04 := not ai and not bi and not ci and not di;
100	      l13 := (not aeqb and not ci and not di) or
101	             (not ceqd and not ai and not bi);
102	      l31 := (not aeqb and ci and di) or
103	             (not ceqd and ai and bi);
104	
105	      -- The 5B/6B encoding
106	
107	      ao := ai;
108	      bo := (bi and not l40) or l04;
109	      co := l04 or ci or (ei and di and not ci and not bi and not ai);
110	      do := di and not (ai and bi and ci);
111	      eo := (ei or l13) and not (ei and di and not ci and not bi and not ai);
112	      io := (l22 and not ei) or
113	            (ei and not di and not ci and not (ai and bi)) or  -- D16, D17, D18
114	            (ei and l40) or
115	            (ki and ei and di and ci and not bi and not ai) or  -- K.28
116	            (ei and not di and ci and not bi and not ai);
117	
118	      -- pds16 indicates cases where d-1 is assumed + to get our encoded value
119	      pd1s6 := (ei and di and not ci and not bi and not ai) or (not ei and not l22 and not l31);
120	      -- nds16 indicates cases where d-1 is assumed - to get our encoded value
121	      nd1s6 := ki or (ei and not l22 and not l13) or (not ei and not di and ci and bi and ai);
122	
123	      -- ndos6 is pds16 cases where d-1 is + yields - disp out - all of them
124	      ndos6 := pd1s6;
125	      -- pdos6 is nds16 cases where d-1 is - yields + disp out - all but one
126	      pdos6 := ki or (ei and not l22 and not l13);
127	
128	
129	      -- some Dx.7 and all Kx.7 cases result in run length of 5 case unless
130	      -- an alternate coding is used (referred to as Dx.A7, normal is Dx.P7)
131	      -- specifically, D11, D13, D14, D17, D18, D19.
132	      if (dispIn = '1') then
133	         alt6 := (not ei and di and l31);
134	      else
135	         alt6 := (ei and not di and l13);
136	      end if;
137	      alt7 := fi and gi and hi and (ki or alt6);
138	
139	      fo := fi and not alt7;
140	      go := gi or (not fi and not gi and not hi);
141	      ho := hi;
142	      jo := (not hi and (gi xor fi)) or alt7;
143	
144	      -- nd1s4 is cases where d-1 is assumed - to get our encoded value
145	      nd1s4 := fi and gi;
146	      -- pd1s4 is cases where d-1 is assumed + to get our encoded value
147	      pd1s4 := (not fi and not gi) or (ki and ((fi and not gi) or (not fi and gi)));
148	
149	      -- ndos4 is pd1s4 cases where d-1 is + yields - disp out - just some
150	      ndos4 := (not fi and not gi);
151	      -- pdos4 is nd1s4 cases where d-1 is - yields + disp out
152	      pdos4 := fi and gi and hi;
153	
154	      -- only legal K codes are K28.0- > .7, K23/27/29/30.7
155	      -- K28.0- > 7 is ei = di = ci = 1, bi = ai = 0
156	      -- K23 is 10111
157	      -- K27 is 11011
158	      -- K29 is 11101
159	      -- K30 is 11110 - so K23/27/29/30 are ei and l31
160	      illegalk := ki and
161	                  (ai or bi or not ci or not di or not ei) and  -- not K28.0- > 7
162	                  (not fi or not gi or not hi or not ei or not l31);  -- not K23/27/29/30.7
163	
164	      -- now determine whether to do the complementing
165	      -- complement if prev disp is - and pd1s6 is set, or + and nd1s6 is set
166	      compls6 := (pd1s6 and not dispin) or (nd1s6 and dispin);
167	
168	      -- disparity out of 5b6b is disp in with pdso6 and ndso6
169	      -- pds16 indicates cases where d-1 is assumed + to get our encoded value
170	      -- ndos6 is cases where d-1 is + yields - disp out
171	      -- nds16 indicates cases where d-1 is assumed - to get our encoded value
172	      -- pdos6 is cases where d-1 is - yields + disp out
173	      -- disp toggles in all ndis16 cases, and all but that 1 nds16 case
174	
175	      disp6 := dispin xor (ndos6 or pdos6);
176	
177	      compls4 := (pd1s4 and not disp6) or (nd1s4 and disp6);
178	      dispOut := disp6 xor (ndos4 or pdos4);
179	
180	      dataOut := (jo xor compls4) & (ho xor compls4) &
181	                 (go xor compls4) & (fo xor compls4) &
182	                 (io xor compls6) & (eo xor compls6) &
183	                 (do xor compls6) & (co xor compls6) &
184	                 (bo xor compls6) & (ao xor compls6);
185	
186	   end procedure encode8b10b;
187	
188	   procedure decode8b10b (
189	      dataIn   : in  slv(9 downto 0);
190	      dispIn   : in  sl;
191	      dataOut  : out slv(7 downto 0);
192	      dataKOut : out sl;
193	      dispOut  : out sl;
194	      codeErr  : out sl;
195	      dispErr  : out sl)
196	   is
197	      variable ai, bi, ci, di, ei, ii, fi, gi, hi, ji      : sl;
198	      variable aeqb, ceqd                                  : sl;
199	      variable p22, p13, p31, p40, p04                     : sl;
200	      variable disp6a, disp6a2, disp6a0, disp6b            : sl;
201	      variable p22bceeqi, p22bncneeqi, p13in, p31i, p13dei : sl;
202	      variable p22aceeqi, p22ancneeqi                      : sl;
203	      variable p13en, anbnenin, abei, cdei, cndnenin       : sl;
204	      variable p22enin, p22ei, p31dnenin, p31e             : sl;
205	      variable compa, compb, compc, compd, compe           : sl;
206	      variable ao, bo, co, do, eo, ko, fo, go, ho          : sl;
207	      variable feqg, heqj, fghj22, fghjp13, fghjp31        : sl;
208	      variable alt7, k28, k28p                             : sl;
209	      variable disp6p, disp6n, disp4p, disp4n              : sl;
210	   begin
211	
212	      ai := dataIn(0);
213	      bi := dataIn(1);
214	      ci := dataIn(2);
215	      di := dataIn(3);
216	      ei := dataIn(4);
217	      ii := dataIn(5);
218	      fi := dataIn(6);
219	      gi := dataIn(7);
220	      hi := dataIn(8);
221	      ji := dataIn(9);
222	
223	      aeqb := (ai and bi) or (not ai and not bi);
224	      ceqd := (ci and di) or (not ci and not di);
225	      p22  := (ai and bi and not ci and not di) or
226	             (ci and di and not ai and not bi) or
227	             (not aeqb and not ceqd);
228	      p13 := (not aeqb and not ci and not di) or
229	             (not ceqd and not ai and not bi);
230	      p31 := (not aeqb and ci and di) or
231	             (not ceqd and ai and bi);
232	
233	      p40 := ai and bi and ci and di;
234	      p04 := not ai and not bi and not ci and not di;
235	
236	      disp6a  := p31 or (p22 and dispin);  -- pos disp if p22 and was pos, or p31.
237	      disp6a2 := p31 and dispin;        -- disp is ++ after 4 bits
238	      disp6a0 := p13 and not dispin;    -- -- disp after 4 bits
239	
240	      disp6b := (((ei and ii and not disp6a0) or (disp6a and (ei or ii)) or disp6a2 or
241	                  (ei and ii and di)) and (ei or ii or di));
242	
243	      -- The 5B/6B decoding special cases where ABCDE not = abcde
244	
245	      p22bceeqi   := p22 and bi and ci and (ei xnor ii);
246	      p22bncneeqi := p22 and not bi and not ci and (ei xnor ii);
247	      p13in       := p13 and not ii;
248	      p31i        := p31 and ii;
249	      p13dei      := p13 and di and ei and ii;
250	      p22aceeqi   := p22 and ai and ci and (ei xnor ii);
251	      p22ancneeqi := p22 and not ai and not ci and (ei xnor ii);
252	      p13en       := p13 and not ei;
253	      anbnenin    := not ai and not bi and not ei and not ii;
254	      abei        := ai and bi and ei and ii;
255	      cdei        := ci and di and ei and ii;
256	      cndnenin    := not ci and not di and not ei and not ii;
257	
258	      -- non-zero disparity cases:
259	      p22enin   := p22 and not ei and not ii;
260	      p22ei     := p22 and ei and ii;
261	      -- p13in := p12 and not ii ;
262	      -- p31i := p31 and ii ;
263	      p31dnenin := p31 and not di and not ei and not ii;
264	      -- p13dei := p13 and di and ei and ii ;
265	      p31e      := p31 and ei;
266	
267	      compa := p22bncneeqi or p31i or p13dei or p22ancneeqi or
268	               p13en or abei or cndnenin;
269	      compb := p22bceeqi or p31i or p13dei or p22aceeqi or
270	               p13en or abei or cndnenin;
271	      compc := p22bceeqi or p31i or p13dei or p22ancneeqi or
272	               p13en or anbnenin or cndnenin;
273	      compd := p22bncneeqi or p31i or p13dei or p22aceeqi or
274	               p13en or abei or cndnenin;
275	      compe := p22bncneeqi or p13in or p13dei or p22ancneeqi or
276	               p13en or anbnenin or cndnenin;
277	
278	      ao := ai xor compa;
279	      bo := bi xor compb;
280	      co := ci xor compc;
281	      do := di xor compd;
282	      eo := ei xor compe;
283	
284	      feqg   := (fi and gi) or (not fi and not gi);
285	      heqj   := (hi and ji) or (not hi and not ji);
286	      fghj22 := (fi and gi and not hi and not ji) or
287	                (not fi and not gi and hi and ji) or
288	                (not feqg and not heqj);
289	      fghjp13 := (not feqg and not hi and not ji) or
290	                 (not heqj and not fi and not gi);
291	      fghjp31 := ((not feqg) and hi and ji) or
292	                 (not heqj and fi and gi);
293	
294	      dispout := (fghjp31 or (disp6b and fghj22) or (hi and ji)) and (hi or ji);
295	
296	      ko := ((ci and di and ei and ii) or (not ci and not di and not ei and not ii) or
297	             (p13 and not ei and ii and gi and hi and ji) or
298	             (p31 and ei and not ii and not gi and not hi and not ji));
299	
300	      alt7 := (fi and not gi and not hi and  -- 1000 cases, where disp6b is 1
301	               ((dispin and ci and di and not ei and not ii) or ko or
302	                (dispin and not ci and di and not ei and not ii))) or
303	              (not fi and gi and hi and      -- 0111 cases, where disp6b is 0
304	               ((not dispin and not ci and not di and ei and ii) or ko or
305	                (not dispin and ci and not di and ei and ii)));
306	
307	      k28  := (ci and di and ei and ii) or not (ci or di or ei or ii);
308	      -- k28 with positive disp into fghi - .1, .2, .5, and .6 special cases
309	      k28p := not (ci or di or ei or ii);
310	      fo   := (ji and not fi and (hi or not gi or k28p)) or
311	            (fi and not ji and (not hi or gi or not k28p)) or
312	            (k28p and gi and hi) or
313	            (not k28p and not gi and not hi);
314	      go := (ji and not fi and (hi or not gi or not k28p)) or
315	            (fi and not ji and (not hi or gi or k28p)) or
316	            (not k28p and gi and hi) or
317	            (k28p and not gi and not hi);
318	      ho := ((ji xor hi) and not ((not fi and gi and not hi and ji and not k28p) or (not fi and gi and hi and not ji and k28p) or
319	                                  (fi and not gi and not hi and ji and not k28p) or (fi and not gi and hi and not ji and k28p))) or
320	            (not fi and gi and hi and ji) or (fi and not gi and not hi and not ji);
321	
322	      disp6p := (p31 and (ei or ii)) or (p22 and ei and ii);
323	      disp6n := (p13 and not (ei and ii)) or (p22 and not ei and not ii);
324	      disp4p := fghjp31;
325	      disp4n := fghjp13;
326	
327	      codeErr := p40 or p04 or (fi and gi and hi and ji) or (not fi and not gi and not hi and not ji) or
328	                 (p13 and not ei and not ii) or (p31 and ei and ii) or
329	                 (ei and ii and fi and gi and hi) or (not ei and not ii and not fi and not gi and not hi) or
330	                 (ei and not ii and gi and hi and ji) or (not ei and ii and not gi and not hi and not ji) or
331	                 (not p31 and ei and not ii and not gi and not hi and not ji) or
332	                 (not p13 and not ei and ii and gi and hi and ji) or
333	                 (((ei and ii and not gi and not hi and not ji) or
334	                   (not ei and not ii and gi and hi and ji)) and
335	                  not ((ci and di and ei) or (not ci and not di and not ei))) or
336	                 (disp6p and disp4p) or (disp6n and disp4n) or
337	                 (ai and bi and ci and not ei and not ii and ((not fi and not gi) or fghjp13)) or
338	                 (not ai and not bi and not ci and ei and ii and ((fi and gi) or fghjp31)) or
339	                 (fi and gi and not hi and not ji and disp6p) or
340	                 (not fi and not gi and hi and ji and disp6n) or
341	                 (ci and di and ei and ii and not fi and not gi and not hi) or
342	                 (not ci and not di and not ei and not ii and fi and gi and hi);
343	
344	      dataOut  := ho & go & fo & eo & do & co & bo & ao;
345	      dataKOut := ko;
346	
347	      --my disp err fires for any legal codes that violate disparity, may fire for illegal codes
348	      dispErr := ((dispin and disp6p) or (disp6n and not dispin) or
349	                  (dispin and not disp6n and fi and gi) or
350	                  (dispin and ai and bi and ci) or
351	                  (dispin and not disp6n and disp4p) or
352	                  (not dispin and not disp6p and not fi and not gi) or
353	                  (not dispin and not ai and not bi and not ci) or
354	                  (not dispin and not disp6p and disp4n) or
355	                  (disp6p and disp4p) or (disp6n and disp4n));
356	
357	   end procedure decode8b10b;
358	
359	end package body Code8b10bPkg;
360

