41	   function hammingEccPartiyWidth (k : positive) return positive is
42	      variable m : positive;
43	   begin
44	      -- Init
45	      m := 1;
46	
47	      -----------------------------------
48	      -- Calculate number of parity bits:
49	      -----------------------------------
50	      -- k = 2^m - m  - 1
51	      --    where k is data bits
52	      --    where m is parity bits
53	      -----------------------------------
54	      while (2**m < k+m+1) loop
55	         m := m + 1;
56	      end loop;
57	
58	      -- Return the results
59	      return m;
60	   end function;
