62	   function hammingEccDataWidth (k : positive) return positive is
63	      variable m : positive;
64	      variable n : positive;
65	   begin
66	      m := hammingEccPartiyWidth(k);
67	      n := m+k;
68	      return n;
69	   end function;
70	
71	   function hammingEccEncode (data : slv) return slv is
72	      constant k         : positive := data'length;
73	      constant m         : positive := hammingEccPartiyWidth(k);
74	      constant n         : positive := hammingEccDataWidth(k);
75	      variable bitPtr    : natural;
76	      variable codeWord  : slv(n downto 1);
77	      variable pVector   : slv(m downto 1);
78	      variable pExtended : sl;
79	      variable encWord   : slv(n downto 0);
80	   begin
81	      -- Init
82	      bitPtr   := 0;
83	      codeWord := (others => '0');
84	      pVector  := (others => '0');
85	
86	      -- Put the data bits in the correct location
87	      for i in 1 to n loop
88	         if (isPowerOf2(i) = false) then
89	            codeWord(i) := data(bitPtr);
90	            bitPtr      := bitPtr + 1;
91	         end if;
92	      end loop;
93	
94	      -- Calculate the parity vector
95	      for i in 1 to m loop
96	         for j in 1 to n loop
97	            if uOr(toSlv(2**(i-1), n) and toSlv(j, n)) = '1' then
98	               pVector(i) := pVector(i) xor codeWord(j);
99	            end if;
100	         end loop;
101	      end loop;
102	
103	      -- Put the parity bits in the correct location
104	      for i in 1 to m loop
105	         codeWord(2**(i-1)) := pVector(i);
106	      end loop;
107	
108	      -- Calculate extended parity bit
109	      pExtended := uXor(codeWord);
110	
111	      -- Set the output encoded data bus
112	      encWord := codeWord & pExtended;
113	
114	      -- Return the results
115	      return encWord;
116	   end function;
117	
118	   procedure hammingEccDecode (
119	      encWord : in    slv;
120	      data    : inout slv;
121	      errSbit : inout sl;
122	      errDbit : inout sl) is
123	      constant k        : positive := data'length;
124	      constant m        : positive := hammingEccPartiyWidth(k);
125	      constant n        : positive := hammingEccDataWidth(k);
126	      variable bitPtr   : natural;
127	      variable parity   : sl;
128	      variable syndrome : slv(m downto 1);
129	      variable codeWord : slv(n downto 0);
130	   begin
131	      -- Init
132	      bitPtr   := 0;
133	      data     := toSlv(0, data'length);
134	      errSbit  := '0';
135	      errDbit  := '0';
136	      syndrome := (others => '0');
137	      codeWord := encWord;
138	
139	      -- Calculate parity
140	      parity := uXor(encWord);
141	
142	      -- Calculate syndrome
143	      for i in 1 to m loop
144	         for j in 1 to n loop
145	            if uOr(toSlv(2**(i-1), n) and toSlv(j, n)) = '1' then
146	               syndrome(i) := syndrome(i) xor encWord(j);
147	            end if;
148	         end loop;
149	      end loop;
150	
151	      -- Correct the code word
152	      if (conv_integer(syndrome) <= n) then
153	         codeWord(conv_integer(syndrome)) := not(codeWord(conv_integer(syndrome)));
154	      end if;
155	
156	      -- Get the data bits in the correct location
157	      for i in 1 to n loop
158	         if (isPowerOf2(i) = false) then
159	            data(bitPtr) := codeWord(i);
160	            bitPtr       := bitPtr + 1;
161	         end if;
162	      end loop;
163	
164	      -- Set the status flags
165	      errSbit := parity or uOr(syndrome);
166	      errDbit := not(parity) and uOr(syndrome);
