30	entity AxiStreamDepacketizer is
31	   generic (
32	      TPD_G                : time    := 1 ns;
33	      RST_ASYNC_G          : boolean := false;
34	      INPUT_PIPE_STAGES_G  : integer := 0;
35	      OUTPUT_PIPE_STAGES_G : integer := 0);
