42	
43	      sAxisMaster : in  AxiStreamMasterType;
44	      sAxisSlave  : out AxiStreamSlaveType;
45	
46	      mAxisMaster : out AxiStreamMasterType;
47	      mAxisSlave  : in  AxiStreamSlaveType);
48	end entity AxiStreamDepacketizer;
49	
50	architecture rtl of AxiStreamDepacketizer is
51	
52	   constant AXIS_CONFIG_C : AxiStreamConfigType := (
53	      TSTRB_EN_C    => false,
54	      TDATA_BYTES_C => 8,
55	      TDEST_BITS_C  => 8,
56	      TID_BITS_C    => 8,
57	      TKEEP_MODE_C  => TKEEP_NORMAL_C,
58	      TUSER_BITS_C  => 8,
59	      TUSER_MODE_C  => TUSER_FIRST_LAST_C);
60	
61	   constant VERSION_C : slv(3 downto 0) := "0000";
62	
63	   type StateType is (HEADER_S, BLEED_S, MOVE_S, DONE_S);
64	
65	   type RegType is record
66	      state            : StateType;
67	      frameNumber      : slv(11 downto 0);
68	      packetNumber     : slv(23 downto 0);
69	      sof              : sl;
70	      startup          : sl;
71	      sideband         : sl;
72	      inputAxisSlave   : AxiStreamSlaveType;
73	      outputAxisMaster : AxiStreamMasterArray(1 downto 0);
74	   end record RegType;
75	
76	   constant REG_INIT_C : RegType := (
77	      state            => HEADER_S,
78	      frameNumber      => (others => '0'),
79	      packetNumber     => (others => '0'),
80	      sof              => '1',
81	      startup          => '1',
82	      sideband         => '0',
83	      inputAxisSlave   => AXI_STREAM_SLAVE_INIT_C,
84	      outputAxisMaster => (others => axiStreamMasterInit(AXIS_CONFIG_C)));
85	
86	   signal r   : RegType := REG_INIT_C;
87	   signal rin : RegType;
88	
89	   signal inputAxisMaster  : AxiStreamMasterType;
90	   signal inputAxisSlave   : AxiStreamSlaveType;
91	   signal outputAxisMaster : AxiStreamMasterType;
92	   signal outputAxisSlave  : AxiStreamSlaveType;
93	
94	   -- attribute dont_touch                     : string;
95	   -- attribute dont_touch of r                : signal is "TRUE";
96	   -- attribute dont_touch of inputAxisMaster  : signal is "TRUE";
97	   -- attribute dont_touch of inputAxisSlave   : signal is "TRUE";
98	   -- attribute dont_touch of outputAxisMaster : signal is "TRUE";
99	   -- attribute dont_touch of outputAxisSlave  : signal is "TRUE";
100	
101	begin
102	
103	   -----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
104	   -- Input pipeline
105	   -----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
106	   U_AxiStreamPipeline_Input : entity surf.AxiStreamPipeline
107	      generic map (
108	         TPD_G         => TPD_G,
109	         RST_ASYNC_G   => RST_ASYNC_G,
110	         PIPE_STAGES_G => INPUT_PIPE_STAGES_G)
111	      port map (
112	         axisClk     => axisClk,          -- [in]
113	         axisRst     => axisRst,          -- [in]
114	         sAxisMaster => sAxisMaster,      -- [in]
115	         sAxisSlave  => sAxisSlave,       -- [out]
116	         mAxisMaster => inputAxisMaster,  -- [out]
117	         mAxisSlave  => inputAxisSlave);  -- [in]
118	
119	   -----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
120	   -- Output pipeline
121	   -----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
122	   U_AxiStreamPipeline_Output : entity surf.AxiStreamPipeline
123	      generic map (
124	         TPD_G         => TPD_G,
125	         RST_ASYNC_G   => RST_ASYNC_G,
126	         PIPE_STAGES_G => OUTPUT_PIPE_STAGES_G)
127	      port map (
128	         axisClk     => axisClk,           -- [in]
129	         axisRst     => axisRst,           -- [in]
130	         sAxisMaster => outputAxisMaster,  -- [in]
131	         sAxisSlave  => outputAxisSlave,   -- [out]
132	         mAxisMaster => mAxisMaster,       -- [out]
133	         mAxisSlave  => mAxisSlave);       -- [in]
134	
135	   -------------------------------------------------------------------------------------------------
136	   -- Accumulation sequencing, DMA ring buffer, and AXI-Lite logic
137	   -------------------------------------------------------------------------------------------------
138	   comb : process (axisRst, inputAxisMaster, outputAxisSlave, r, restart) is
139	      variable v : RegType;
140	
141	   begin
142	      -- Latch the current value
143	      v := r;
144	
145	      -- Check for restart
146	      if (restart = '1') then
147	         v.startup := '1';
148	         v.sof     := '1';
149	      end if;
150	
151	      -- Reset tready by default
152	      v.inputAxisSlave.tready := '0';
153	
154	      -- Check if data accepted
155	      if (outputAxisSlave.tReady = '1') then
156	         v.outputAxisMaster(1).tValid := '0';
157	         v.outputAxisMaster(0).tValid := '0';
158	      end if;
159	
160	      case r.state is
161	         ----------------------------------------------------------------------
162	         when HEADER_S =>
163	            -- Accept new data
164	            v.inputAxisSlave.tready := '1';
165	
166	            -- Initialize the AXIS[1] buffer
167	            v.outputAxisMaster(1) := axiStreamMasterInit(AXIS_CONFIG_C);
168	
169	            -- Advance the output pipeline
170	            if (r.outputAxisMaster(1).tValid = '1' and v.outputAxisMaster(0).tValid = '0') then
171	               v.outputAxisMaster(0) := r.outputAxisMaster(1);
172	            end if;
173	
174	            -- Process an incoming transaction (which should be the header)
175	            if (inputAxisMaster.tValid = '1' and v.outputAxisMaster(1).tValid = '0') then
176	
177	               -- Default next state if v.state=MOVE_S not applied later in the combinatorial chain
178	               v.state := MOVE_S;
179	
180	               -- Assign sideband fields
181	               v.outputAxisMaster(1).tDest(7 downto 0) := inputAxisMaster.tData(47 downto 40);
182	               v.outputAxisMaster(1).tId(7 downto 0)   := inputAxisMaster.tData(55 downto 48);
183	               v.outputAxisMaster(1).tUser(7 downto 0) := inputAxisMaster.tData(63 downto 56);
184	
185	               -- Assert SOF if starting a new frame
186	               axiStreamSetUserBit(AXIS_CONFIG_C, v.outputAxisMaster(1), SSI_SOF_C, r.sof, 0);  -- SOF
187	
188	               -- Reset the SOF flag
189	               v.sof := '0';
190	
191	               -- Check for SOF
192	               if (r.sof = '1') then
193	                  -- Update local copy of frame number
194	                  v.frameNumber  := inputAxisMaster.tData(15 downto 4);
195	                  -- Check the packet number because SOF
196	                  v.packetNumber := (others => '0');
197	                  -- Check for errors
198	                  if ((r.startup = '0' and inputAxisMaster.tData(15 downto 4) /= r.frameNumber+1) or  -- not first value after startup and misalignment in frame number
199	                      inputAxisMaster.tData(39 downto 16) /= 0) then  -- packet number != 0
200	                     -- Next state
201	                     v.state := BLEED_S;  -- Error - Missing frames
202	                  end if;
203	               -- Else this is a continuation
204	               else
205	                  -- Update local copy of packet number
206	                  v.packetNumber := inputAxisMaster.tData(39 downto 16);
207	                  -- Check for errors
208	                  if (inputAxisMaster.tData(15 downto 4) /= r.frameNumber or  -- new frame number != local copy of frame number
209	                      inputAxisMaster.tData(39 downto 16) /= r.packetNumber+1) then  -- packet number increment by 1 with respect to local copy of packet number
210	                     -- Terminate the packet
211	                     v.outputAxisMaster(1).tvalid := '1';
212	                     v.outputAxisMaster(1).tlast  := '1';
213	                     -- Set the EOFE flag
214	                     axiStreamSetUserBit(AXIS_CONFIG_C, v.outputAxisMaster(1), SSI_EOFE_C, '1', 0);
215	                     -- Next state
216	                     v.state                      := BLEED_S;
217	                  end if;
218	               end if;
219	               -- Update the flags
220	               v.startup  := '0';
221	               v.sideband := '1';
222	            end if;
223	         ----------------------------------------------------------------------
224	         when BLEED_S =>
225	            -- Blow off the data
226	            v.inputAxisSlave.tready      := '1';
227	            v.outputAxisMaster(1).tvalid := '0';
228	            -- Set startup and SOF true
229	            v.sof                        := '1';
230	            v.startup                    := '1';
231	            -- Check for EOF
232	            if (inputAxisMaster.tLast = '1') then
233	               v.state := HEADER_S;
234	            end if;
235	         ----------------------------------------------------------------------
236	         when MOVE_S =>
237	            -- Keep the caches copy
238	            v.outputAxisMaster(1).tvalid := r.outputAxisMaster(1).tvalid;
239	            -- Check if we can move data
240	            if (inputAxisMaster.tValid = '1' and v.outputAxisMaster(0).tValid = '0') then
241	               -- Accept the data
242	               v.inputAxisSlave.tReady     := '1';
243	               -- Advance the pipeline
244	               v.outputAxisMaster(1)       := inputAxisMaster;
245	               v.outputAxisMaster(0)       := r.outputAxisMaster(1);
246	               -- Keep sideband data from header
247	               v.outputAxisMaster(1).tDest := r.outputAxisMaster(1).tDest;
248	               v.outputAxisMaster(1).tId   := r.outputAxisMaster(1).tId;
249	               -- Check for sideband
250	               if (r.sideband = '1') then
251	                  -- But tUser only for first output txn
252	                  v.outputAxisMaster(1).tUser := r.outputAxisMaster(1).tUser;
253	                  -- Reset the flag
254	                  v.sideband                  := '0';
255	               end if;
256	               -- End of frame
257	               if (inputAxisMaster.tLast = '1') then
258	                  -- Check tkeep to find tail byte (and strip it out)
259	                  v.outputAxisMaster(1).tKeep(15 downto 0) := '0' & inputAxisMaster.tKeep(15 downto 1);
260	                  case (inputAxisMaster.tKeep(7 downto 0)) is
261	                     when X"01" =>
262	                        -- Single byte tail, append tUser to previous txn which has been held
263	                        v.outputAxisMaster(1).tValid              := '0';
264	                        v.outputAxisMaster(0).tUser(63 downto 56) := '0' & inputAxisMaster.tData(6 downto 0);
265	                        v.outputAxisMaster(0).tLast               := inputAxisMaster.tData(7);
266	                        v.sof                                     := inputAxisMaster.tData(7);
267	                     when X"03" =>
268	                        v.outputAxisMaster(1).tUser(7 downto 0) := '0' & inputAxisMaster.tData(14 downto 8);
269	                        v.sof                                   := inputAxisMaster.tData(15);
270	                     when X"07" =>
271	                        v.outputAxisMaster(1).tUser(15 downto 8) := '0' & inputAxisMaster.tData(22 downto 16);
272	                        v.sof                                    := inputAxisMaster.tData(23);
273	                     when X"0F" =>
274	                        v.outputAxisMaster(1).tUser(23 downto 16) := '0' & inputAxisMaster.tData(30 downto 24);
275	                        v.sof                                     := inputAxisMaster.tData(31);
276	                     when X"1F" =>
277	                        v.outputAxisMaster(1).tUser(31 downto 24) := '0' & inputAxisMaster.tData(38 downto 32);
278	                        v.sof                                     := inputAxisMaster.tData(39);
279	                     when X"3F" =>
280	                        v.outputAxisMaster(1).tUser(39 downto 32) := '0' & inputAxisMaster.tData(46 downto 40);
281	                        v.sof                                     := inputAxisMaster.tData(47);
282	                     when X"7F" =>
283	                        v.outputAxisMaster(1).tUser(47 downto 40) := '0' & inputAxisMaster.tData(54 downto 48);
284	                        v.sof                                     := inputAxisMaster.tData(55);
285	                     when X"FF" =>
286	                        v.outputAxisMaster(1).tUser(55 downto 48) := '0' & inputAxisMaster.tData(62 downto 56);
287	                        v.sof                                     := inputAxisMaster.tData(63);
288	                     when others =>
289	                        null;
290	                  end case;
291	                  v.outputAxisMaster(1).tLast := v.sof;
292	                  v.state                     := DONE_S;
293	               end if;
294	            end if;
295	         ----------------------------------------------------------------------
296	         when DONE_S =>
297	            -- Keep the caches copy
298	            v.outputAxisMaster(1).tvalid := r.outputAxisMaster(1).tvalid;
299	            -- Check if we can move data
300	            if (v.outputAxisMaster(0).tValid = '0') then
301	               -- Advance the pipeline
302	               v.outputAxisMaster(1).tValid := '0';
303	               v.outputAxisMaster(0)        := r.outputAxisMaster(1);
304	               v.state                      := HEADER_S;
305	            end if;
306	         ----------------------------------------------------------------------
307	         when others =>  -- For ASIC designs it is best to declare a 'Default' state which returns to HEADER_S state
308	            v := REG_INIT_C;
309	      ----------------------------------------------------------------------
310	      end case;
311	
312	      -- Combinatorial outputs before the reset
313	      inputAxisSlave <= v.inputAxisSlave;
314	
315	      -- Reset
316	      if (RST_ASYNC_G = false and axisRst = '1') then
317	         v := REG_INIT_C;
318	      end if;
319	
320	      -- Register the variable for next clock cycle
321	      rin <= v;
322	
323	      -- Hold each out tvalid until next in tvalid arrives
324	      outputAxisMaster <= r.outputAxisMaster(0);
325	
326	   end process comb;
327	
328	   seq : process (axisClk, axisRst) is
329	   begin
330	      if (RST_ASYNC_G and axisRst = '1') then
331	         r <= REG_INIT_C after TPD_G;
332	      elsif rising_edge(axisClk) then
333	         r <= rin after TPD_G;
334	      end if;
335	   end process seq;
336	
337	end architecture rtl;
